(window.webpackJsonp=window.webpackJsonp||[]).push([[142],{1409:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-class\\"><span class=\\"hljs-keyword\\">class</span> <span class=\\"hljs-title\\">Solution</span><span class=\\"hljs-params\\">(object)</span>:</span>\\n    <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">def</span> <span class=\\"hljs-title\\">kthSmallestPrimeFraction</span><span class=\\"hljs-params\\">(self, A, K)</span>:</span>\\n        <span class=\\"hljs-string\\">\\"\\"\\"\\n        :type A: List[int]\\n        :type K: int\\n        :rtype: List[int]\\n        \\"\\"\\"</span>\\n        N=len(A)\\n        lo,hi=<span class=\\"hljs-number\\">0</span>,<span class=\\"hljs-number\\">1</span>\\n        candidate=<span class=\\"hljs-literal\\">None</span>\\n        <span class=\\"hljs-keyword\\">while</span> <span class=\\"hljs-literal\\">True</span>:\\n          mid=float((lo+hi)/<span class=\\"hljs-number\\">2</span>)\\n          i,j=N<span class=\\"hljs-number\\">-1</span>,N<span class=\\"hljs-number\\">-2</span>\\n          count=<span class=\\"hljs-number\\">0</span>\\n          minGap=float(<span class=\\"hljs-string\\">\'inf\'</span>)\\n          <span class=\\"hljs-keyword\\">while</span> i&gt;=<span class=\\"hljs-number\\">0</span> <span class=\\"hljs-keyword\\">and</span> j&gt;=<span class=\\"hljs-number\\">0</span>:\\n            cur=float(A[j])/float(A[i])\\n            <span class=\\"hljs-comment\\"># print cur,mid,count,minGap</span>\\n            <span class=\\"hljs-keyword\\">if</span> cur&lt;=mid:\\n              <span class=\\"hljs-keyword\\">if</span> abs(cur-mid)&lt;minGap:\\n                minGap=abs(cur-mid)\\n                candidate=[A[j],A[i]]\\n              count+=j+<span class=\\"hljs-number\\">1</span>\\n              i-=<span class=\\"hljs-number\\">1</span>\\n              <span class=\\"hljs-keyword\\">if</span> i==j:\\n                j-=<span class=\\"hljs-number\\">1</span>\\n            <span class=\\"hljs-keyword\\">else</span>:\\n              j-=<span class=\\"hljs-number\\">1</span>\\n          <span class=\\"hljs-comment\\"># print mid,count,\'---\'</span>\\n          <span class=\\"hljs-keyword\\">if</span> count&lt;K:\\n            lo=mid\\n          <span class=\\"hljs-keyword\\">elif</span> count&gt;K:\\n            hi=mid\\n          <span class=\\"hljs-keyword\\">else</span>:\\n            <span class=\\"hljs-keyword\\">return</span> candidate\\n          \\n          \\n</code></pre>\\n"],"titleSlug":"k-th-smallest-prime-fraction","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u6309\u9012\u589e\u987a\u5e8f\u6392\u5e8f\u7684\u6570\u7ec4 <code>arr</code> \u548c\u4e00\u4e2a\u6574\u6570 <code>k</code> \u3002\u6570\u7ec4 <code>arr</code> \u7531 <code>1</code> \u548c\u82e5\u5e72 <strong>\u7d20\u6570</strong>\xa0 \u7ec4\u6210\uff0c\u4e14\u5176\u4e2d\u6240\u6709\u6574\u6570\u4e92\u4e0d\u76f8\u540c\u3002</p>\\n\\n<p>\u5bf9\u4e8e\u6bcf\u5bf9\u6ee1\u8db3 <code>0 < i < j < arr.length</code> \u7684 <code>i</code> \u548c <code>j</code> \uff0c\u53ef\u4ee5\u5f97\u5230\u5206\u6570 <code>arr[i] / arr[j]</code> \u3002</p>\\n\\n<p>\u90a3\u4e48\u7b2c\xa0<code>k</code>\xa0\u4e2a\u6700\u5c0f\u7684\u5206\u6570\u662f\u591a\u5c11\u5462?\xa0 \u4ee5\u957f\u5ea6\u4e3a 2 \u7684\u6574\u6570\u6570\u7ec4\u8fd4\u56de\u4f60\u7684\u7b54\u6848, \u8fd9\u91cc\xa0<code>answer[0] == arr[i]</code>\xa0\u4e14\xa0<code>answer[1] == arr[j]</code> \u3002</p>\\n\xa0\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>arr = [1,2,3,5], k = 3\\n<strong>\u8f93\u51fa\uff1a</strong>[2,5]\\n<strong>\u89e3\u91ca\uff1a</strong>\u5df2\u6784\u9020\u597d\u7684\u5206\u6570,\u6392\u5e8f\u540e\u5982\u4e0b\u6240\u793a: \\n1/5, 1/3, 2/5, 1/2, 3/5, 2/3\\n\u5f88\u660e\u663e\u7b2c\u4e09\u4e2a\u6700\u5c0f\u7684\u5206\u6570\u662f 2/5\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>arr = [1,7], k = 1\\n<strong>\u8f93\u51fa\uff1a</strong>[1,7]\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>2 <= arr.length <= 1000</code></li>\\n\\t<li><code>1 <= arr[i] <= 3 * 10<sup>4</sup></code></li>\\n\\t<li><code>arr[0] == 1</code></li>\\n\\t<li><code>arr[i]</code> \u662f\u4e00\u4e2a <strong>\u7d20\u6570</strong> \uff0c<code>i > 0</code></li>\\n\\t<li><code>arr</code> \u4e2d\u7684\u6240\u6709\u6570\u5b57 <strong>\u4e92\u4e0d\u76f8\u540c</strong> \uff0c\u4e14\u6309 <strong>\u4e25\u683c\u9012\u589e</strong> \u6392\u5e8f</li>\\n\\t<li><code>1 <= k <= arr.length * (arr.length - 1) / 2</code></li>\\n</ul>\\n","title":"786. \u7b2c K \u4e2a\u6700\u5c0f\u7684\u7d20\u6570\u5206\u6570","relatedTags":["\u5806","\u4e8c\u5206\u67e5\u627e"],"difficult":"Hard","lang":["python"],"uniqueID":"786"}')}}]);